    /// </summary>
    /// <param name="xmlContent">The XML content as a string</param>
    /// <returns>Dictionary containing configuration key-value pairs</returns>
    public static Dictionary<string, string> ParseConfiguration(string xmlContent)
    {
        if (string.IsNullOrWhiteSpace(xmlContent))
        {
            throw new ArgumentException("XML content cannot be null or empty.", nameof(xmlContent));
        }

        var settings = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);

        // Use XmlReaderSettings with secure defaults to prevent XXE attacks
        // Even though customers may reference external DTDs, we must not resolve them
        // to avoid Server-Side Request Forgery (SSRF) and information disclosure
        var readerSettings = new XmlReaderSettings
        {
            DtdProcessing = DtdProcessing.Prohibit, // Prevent external DTD loading (XXE protection)
            XmlResolver = null, // Do not resolve any external references
            MaxCharactersFromEntities = 1024, // Limit entity expansion
            MaxCharactersInDocument = 10 * 1024 * 1024 // 10MB max document size
        };

        using (var stringReader = new StringReader(xmlContent))
        using (var xmlReader = XmlReader.Create(stringReader, readerSettings))
        {
            var xmlDocument = new XmlDocument
            {
                XmlResolver = null // Also prevent resolution at the document level
            };

            try
            {
                xmlDocument.Load(xmlReader);
            }
            catch (XmlException ex)
            {
                throw new InvalidOperationException(
                    $"Failed to parse XML configuration: {ex.Message}", ex);
            }

            // Extract settings from the document
            ExtractSettings(xmlDocument.DocumentElement, settings, string.Empty);
        }

        return settings;
    }

