    /// <summary>
    /// Parses XML using XmlReader directly for streaming/large file scenarios.
    /// </summary>
    /// <param name="xmlContent">The XML content as a string</param>
    /// <returns>Dictionary containing configuration key-value pairs</returns>
    public static Dictionary<string, string> ParseConfigurationStreaming(string xmlContent)
    {
        if (string.IsNullOrWhiteSpace(xmlContent))
        {
            throw new ArgumentException("XML content cannot be null or empty.", nameof(xmlContent));
        }

        var settings = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);

        var readerSettings = new XmlReaderSettings
        {
            DtdProcessing = DtdProcessing.Prohibit,
            XmlResolver = null,
            MaxCharactersFromEntities = 1024,
            MaxCharactersInDocument = 10 * 1024 * 1024
        };

        var pathStack = new Stack<string>();

        using (var stringReader = new StringReader(xmlContent))
        using (var xmlReader = XmlReader.Create(stringReader, readerSettings))
        {
            while (xmlReader.Read())
            {
                switch (xmlReader.NodeType)
                {
                    case XmlNodeType.Element:
                        pathStack.Push(xmlReader.LocalName);

                        // Extract attributes as settings
                        if (xmlReader.HasAttributes)
                        {
                            string currentPath = string.Join(":", pathStack);
                            while (xmlReader.MoveToNextAttribute())
                            {
                                string attrKey = $"{currentPath}[@{xmlReader.LocalName}]";
                                settings[attrKey] = xmlReader.Value;
                            }
                            xmlReader.MoveToElement();
                        }

                        // If the element is self-closing, pop immediately
                        if (xmlReader.IsEmptyElement)
                        {
                            pathStack.Pop();
                        }
                        break;

                    case XmlNodeType.Text:
                    case XmlNodeType.CDATA:
                        if (pathStack.Count > 0)
                        {
                            string key = string.Join(":", pathStack);
                            if (settings.ContainsKey(key))
                            {
                                // Handle duplicate keys by appending an index
                                int index = 1;
                                string indexedKey;
                                do
                                {
                                    indexedKey = $"{key}[{index}]";
                                    index++;
                                } while (settings.ContainsKey(indexedKey));
                                settings[indexedKey] = xmlReader.Value?.Trim();
                            }
                            else
                            {
                                settings[key] = xmlReader.Value?.Trim();
                            }
                        }
                        break;

                    case XmlNodeType.EndElement:
                        if (pathStack.Count > 0)
                        {
                            pathStack.Pop();
                        }
                        break;
                }
            }
        }

        return settings;
    }

    /// <summary>
    /// Recursively extracts settings from XML nodes into the dictionary.
    /// Uses a colon-separated path as the key (e.g., "database:connection:server").
    /// </summary>
    private static void ExtractSettings(XmlNode node, Dictionary<string, string> settings, string parentPath)
    {
        if (node == null)
        {
            return;
        }

        string currentPath = string.IsNullOrEmpty(parentPath)
            ? node.LocalName
            : $"{parentPath}:{node.LocalName}";

        // Extract attributes
        if (node.Attributes != null)
        {
            foreach (XmlAttribute attr in node.Attributes)
            {
                string attrKey = $"{currentPath}[@{attr.LocalName}]";
                settings[attrKey] = attr.Value;
            }
        }

        // Check if this is a leaf node (contains only text)
        bool isLeaf = true;
        if (node.HasChildNodes)
        {
            foreach (XmlNode child in node.ChildNodes)
            {
                if (child.NodeType == XmlNodeType.Element)
                {
                    isLeaf = false;
                    break;
                }
            }
        }

        if (isLeaf && node.NodeType == XmlNodeType.Element)
        {
            string textContent = node.InnerText?.Trim();
            if (textContent != null)
            {
                if (settings.ContainsKey(currentPath))
                {
                    // Handle duplicate element names by appending an index
                    int index = 1;
                    string indexedKey;
                    do
                    {
                        indexedKey = $"{currentPath}[{index}]";
                        index++;
                    } while (settings.ContainsKey(indexedKey));
                    settings[indexedKey] = textContent;
                }
                else
                {
                    settings[currentPath] = textContent;
                }
            }
        }
        else if (node.HasChildNodes)
        {
            foreach (XmlNode child in node.ChildNodes)
            {
                if (child.NodeType == XmlNodeType.Element)
                {
                    ExtractSettings(child, settings, currentPath);
                }
            }
        }
    }

